INSERT INTO `master` VALUES (1,'Εθνικό και Καποδιστριακό Πανεπιστήμιο Αθηνών','MSc in Computer Science',301,'Σε βάθος θεωρητικό και εφαρμοσμένο πρόγραμμα επιστήμης υπολογιστών με ισχυρή έμφαση στην έρευνα.','https://www.di.uoa.gr','English','Free'),(2,'Οικονομικό Πανεπιστήμιο Αθηνών','MSc in Data Science',401,'Εξειδικευμένο πρόγραμμα στην Επιστήμη Δεδομένων και τη Μηχανική Μάθηση.','https://www.aueb.gr','English','Free / Up to 1,500 EUR (depending on track)'),(3,'Αριστοτέλειο Πανεπιστήμιο Θεσσαλονίκης','MSc in Informatics',401,'Πρόγραμμα υψηλού επιπέδου σε μηχανική λογισμικού, τεχνητή νοημοσύνη και θεωρητική πληροφορική.','https://www.csd.auth.gr','English','Free'),(4,'Τεχνικό Πανεπιστήμιο Μονάχου (TUM)','MSc in Informatics',50,'Κορυφαίο πρόγραμμα με εστίαση στη μηχανική λογισμικού, την τεχνητή νοημοσύνη και τη θεωρητική πληροφορική.','https://www.in.tum.de','English','Free (Semester fee ~150 EUR)'),(5,'Τεχνολογικό Πανεπιστήμιο του Ντελφτ (TU Delft)','MSc Computer Science',60,'Εστιάζει στη μηχανική πολύπλοκων συστημάτων λογισμικού και στη διαχείριση δεδομένων.','https://www.tudelft.nl','English','2,314 EUR / year (EU students)'),(6,'Πανεπιστήμιο της Στουτγκάρδης','MSc Computer Science',251,'Προχωρημένα θέματα στον οπτικό υπολογισμό, αυτόνομα συστήματα και μηχανική υπολογιστών.','https://www.uni-stuttgart.de','English','Free (Semester fee ~200 EUR)'),(7,'Καθολικό Πανεπιστήμιο της Λουβαίν (KU Leuven)','MSc in Artificial Intelligence',80,'Ευρείες θεμελιώδεις και εφαρμοσμένες έννοιες AI και μηχανικής μάθησης σε διεθνές περιβάλλον.','https://www.kuleuven.be','English','1,092 EUR / year (EU students)'),(8,'Πανεπιστήμιο της Σορβόννης','Master in Computer Science',100,'Διερευνά αλγορίθμους, κατανεμημένα συστήματα και αλληλεπίδραση ανθρώπου-υπολογιστή.','https://www.sorbonne-universite.fr','English','243 EUR / year'),(9,'École Polytechnique (Γαλλία)','MSc Computer Science',40,'Κορυφαίο ευρωπαϊκό πρόγραμμα που εξισορροπεί έρευνα αιχμής και βιομηχανική εφαρμογή.','https://www.polytechnique.edu','English','Variable / Competitive scholarships available'),(10,'Πολυτεχνείο του Μιλάνου (Politecnico di Milano)','MSc Informatics',151,'Πολυθεματικό πρόγραμμα που συνδέει την επιστήμη υπολογιστών με τις επιχειρήσεις και τη μηχανική.','https://www.polimi.it','English','895 - 3,900 EUR / year (based on income)'),(11,'Πανεπιστήμιο Σαπιέντσα της Ρώμης','Master in Computer Science',120,'Σε βάθος γνώση στην κυβερνοασφάλεια, ανάπτυξη λογισμικού και θεωρητικά θεμέλια.','https://www.uniroma1.it','English','Up to 2,900 EUR / year (based on income)'),(12,'Βασιλικό Ινστιτούτο Τεχνολογίας KTH','MSc in Machine Learning',70,'Εστιασμένο στην AI, μηχανική μάθηση και ανάλυση δεδομένων σε περιβάλλον υψηλού κύρους.','https://www.kth.se','English','Free for EU/EEA students'),(13,'Πανεπιστήμιο της Λουντ','MSc in Software Engineering',130,'Συνδυάζει τη θεωρία της επιστήμης υπολογιστών με εκτενή πρακτική μηχανική λογισμικού.','https://www.lunduniversity.lu.se','English','Free for EU/EEA students'),(14,'Πανεπιστήμιο του Ελσίνκι','MSc Computer Science',100,'Ένα παγκοσμίως κορυφαίο πρόγραμμα με έμφαση στη θεμελιώδη και εφαρμοσμένη πληροφορική.','https://www.helsinki.fi','English','Free for EU/EEA students'),(15,'Πανεπιστήμιο Aalto','Master\'s Programme in Computer Science',150,'Ισχυρή έμφαση στην ανάπτυξη παιχνιδιών, αλληλεπίδραση ανθρώπου-υπολογιστή και τεχνολογίες μέσων.','https://www.aalto.fi','English','Free for EU/EEA students'),(16,'Πανεπιστήμιο της Βιέννης','MSc Logic and Computation',150,'Αυστηρό πρόγραμμα στη λογική, αλγορίθμους και τεχνητή νοημοσύνη.','https://www.univie.ac.at','English','~20 EUR / semester (EU students)'),(17,'Πανεπιστήμιο της Κύπρου','MSc in Informatics',180,'Εκτενή μαθήματα σε ευφυή συστήματα, big data και δικτύωση.','https://www.ucy.ac.cy','English','1,500 - 3,000 EUR / year'),(18,'Πανεπιστήμιο Λευκωσίας','MSc Computer Science',500,'Εστιάζει στην εφαρμοσμένη πληροφορική, το cloud computing και τεχνολογίες blockchain.','https://www.unic.ac.cy',